VOWELS = set\('aeiouAEIOU'\)

def blend\(a, b\):
    cut_a = max\(2, len\(a\) // 3\)
    for i in range\(cut_a, min\(len\(a\) - 1, cut_a + 3\)\):
        if a[i] in VOWELS:
            cut_a = i + 1
            break
    cut_b = max\(1, len\(b\) // 3\)
    for i in range\(cut_b, min\(len\(b\) - 1, cut_b + 3\)\):
        if b[i] not in VOWELS:
            cut_b = i
            break
    pa, pb = a[:cut_a], b[cut_b:]
    if pa and pb and pa[-1].lower\(\) == pb[0].lower\(\) and pa[-1].lower\(\) not in VOWELS:
        pb = pb[1:]
    return \(pa + pb\).capitalize\(\)

pairs = [
    \('Pakistan', 'Afghanistan'\),
    \('France', 'Germany'\),
    \('China', 'India'\),
    \('Brazil', 'Argentina'\),
    \('Russia', 'Ukraine'\),
    \('Sweden', 'Norway'\),
    \('Pahanistan', 'India'\),   # triple merge test
]
for a, b in pairs:
    print\(f'{a} + {b} = {blend\(a, b\)}'\)
")
